#include <bits/stdc++.h>
using namespace std;
int n,m,num[350],g[5],dp[41][41][41][41];
int main(){
    cin>>n>>m;
    for(int i=1;i<=n;i++)
        cin>>num[i];
    for(int i=1;i<=m;i++){
        int b;
        cin>>b;
        g[b]++;
    }
    dp[0][0][0][0]=num[1];
    for(int a=0;a<=g[1];a++)
        for(int b=0;b<=g[2];b++)
            for(int c=0;c<=g[3];c++)
                for(int d=0;d<=g[4];d++)
                    if(a || b || c || d){
                        int p=a+2*b+3*c+4*d+1;
                        if(a)
                            dp[a][b][c][d]=max(dp[a][b][c][d],dp[a-1][b][c][d]+num[p]);
                        if(b)
                            dp[a][b][c][d]=max(dp[a][b][c][d],dp[a][b-1][c][d]+num[p]);
                        if(c)
                            dp[a][b][c][d]=max(dp[a][b][c][d],dp[a][b][c-1][d]+num[p]);
                        if(d)
                            dp[a][b][c][d]=max(dp[a][b][c][d],dp[a][b][c][d-1]+num[p]);
                    }
    cout<<dp[g[1]][g[2]][g[3]][g[4]];
    return 0;
}
